"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface ScrubBarProps
  extends
    Omit<React.ComponentProps<"div">, "onChange">,
    VariantProps<typeof scrubBarVariants> {
  /** Current value (0-1 normalized) */
  value: number;
  /** Called when value changes during scrubbing */
  onChange?: (value: number) => void;
  /** Called when scrubbing starts */
  onScrubStart?: () => void;
  /** Called when scrubbing ends */
  onScrubEnd?: (value: number) => void;
  /** Format function for tooltip display */
  formatTooltip?: (value: number) => string;
  /** Whether to show a tooltip on hover/scrub */
  showTooltip?: boolean;
  /** Buffer/loaded progress (0-1) shown as lighter fill */
  buffered?: number;
}

// =============================================================================
// VARIANTS
// =============================================================================

const scrubBarVariants = cva(
  "relative w-full cursor-pointer select-none touch-none group",
  {
    variants: {
      size: {
        sm: "h-1",
        md: "h-1.5",
        lg: "h-2",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// COMPONENT
// =============================================================================

function ScrubBar({
  value,
  onChange,
  onScrubStart,
  onScrubEnd,
  formatTooltip,
  showTooltip = false,
  buffered,
  size,
  className,
  ...props
}: ScrubBarProps) {
  const trackRef = React.useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = React.useState(false);
  const [hoverValue, setHoverValue] = React.useState<number | null>(null);

  const getValueFromPointer = React.useCallback((clientX: number): number => {
    const el = trackRef.current;
    if (!el) return 0;
    const rect = el.getBoundingClientRect();
    return Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
  }, []);

  const handlePointerDown = React.useCallback(
    (e: React.PointerEvent) => {
      e.preventDefault();
      setIsDragging(true);
      onScrubStart?.();
      const val = getValueFromPointer(e.clientX);
      onChange?.(val);
      (e.target as HTMLElement).setPointerCapture(e.pointerId);
    },
    [getValueFromPointer, onChange, onScrubStart]
  );

  const handlePointerMove = React.useCallback(
    (e: React.PointerEvent) => {
      const val = getValueFromPointer(e.clientX);
      if (isDragging) {
        onChange?.(val);
      }
      setHoverValue(val);
    },
    [isDragging, getValueFromPointer, onChange]
  );

  const handlePointerUp = React.useCallback(
    (e: React.PointerEvent) => {
      if (isDragging) {
        const val = getValueFromPointer(e.clientX);
        onScrubEnd?.(val);
      }
      setIsDragging(false);
    },
    [isDragging, getValueFromPointer, onScrubEnd]
  );

  const handlePointerLeave = React.useCallback(() => {
    setHoverValue(null);
  }, []);

  const percentage = value * 100;
  const bufferedPercentage = (buffered ?? 0) * 100;

  const thumbSizes = { sm: "w-2.5 h-2.5", md: "w-3 h-3", lg: "w-3.5 h-3.5" };
  const resolvedSize = size ?? "md";

  return (
    <div
      ref={trackRef}
      data-slot="scrub-bar"
      role="slider"
      aria-valuenow={Math.round(value * 100)}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-label="Scrub bar"
      tabIndex={0}
      className={cn(
        scrubBarVariants({ size }),
        "rounded-full bg-muted",
        className
      )}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerLeave={handlePointerLeave}
      {...props}
    >
      {/* Buffered progress */}
      {buffered !== undefined && buffered > 0 && (
        <div
          className="absolute inset-y-0 left-0 rounded-full bg-muted-foreground/20"
          style={{ width: `${bufferedPercentage}%` }}
        />
      )}

      {/* Active progress */}
      <div
        className="absolute inset-y-0 left-0 rounded-full bg-primary transition-[width] duration-75"
        style={{ width: `${percentage}%` }}
      />

      {/* Thumb */}
      <div
        className={cn(
          "absolute top-1/2 -translate-y-1/2 rounded-full bg-primary",
          "opacity-0 group-hover:opacity-100 transition-opacity",
          "shadow-sm",
          isDragging && "opacity-100",
          thumbSizes[resolvedSize]
        )}
        style={{
          left: `${percentage}%`,
          transform: `translate(-50%, -50%)`,
        }}
      />

      {/* Tooltip */}
      {showTooltip && formatTooltip && hoverValue !== null && (
        <div
          className="absolute -top-8 -translate-x-1/2 px-1.5 py-0.5 rounded bg-foreground text-background text-xs font-mono pointer-events-none"
          style={{ left: `${hoverValue * 100}%` }}
        >
          {formatTooltip(isDragging ? value : hoverValue)}
        </div>
      )}
    </div>
  );
}

ScrubBar.displayName = "ScrubBar";

export { ScrubBar, scrubBarVariants };
export type { ScrubBarProps };
